import startsWith from '@andes/common/build/utils/startsWith';
import { EN_US, ES_AR, PT_BR, ZH_CN } from '../constants/locales';

/** @typedef {import('../..').ContextValue} ContextValue */
/** @typedef {import('../..').CreateI18nPgettext} CreateI18nPgettext */
/** @typedef {import('../..').CreateI18nNPgettext} CreateI18nNPgettext */
/** @typedef {import('../..').PrimitiveTypes} PrimitiveTypes */
/** @typedef {import('../..').I18nValues} I18nValues */

const REPLACEMENT_REGEX = /\{(\d+)\}/g;

/**
 * @param {string} text
 * @param {Array<PrimitiveTypes | I18nValues>} replacements */
const replaceArguments = (text, replacements) => text.replace(REPLACEMENT_REGEX, (_, index) => `${replacements[+index]}`);

/**
 * @param {import('@meli/i18n').I18n} i18n
 * @return {CreateI18nPgettext}
 */
const createI18nPgettext = (i18n) => (context, text, ...replacements) => {
  // @ts-expect-error: disabled the rule because 'translations' is a custom property.
  const translationFound = i18n.andes.translations[`${context}\u0004${text}`];

  const usedTranslation = translationFound ? translationFound[1] : text;

  return replaceArguments(usedTranslation, replacements.flat());
};

/**
 * @param {import('@meli/i18n').I18n} i18n
 * @return {CreateI18nNPgettext}
 */
const createI18nNPgettext = (i18n) => (context, singular, plural, quantity, ...replacements) => {
  // @ts-expect-error: disabled the rule because 'translations' is a custom property.
  const translationFound = i18n.andes.translations[`${context}\u0004${singular}`];

  let text;

  if (translationFound) text = (quantity === 1 ? translationFound[1] : translationFound[2]);

  const usedTranslation = text ?? (quantity === 1 ? singular : plural);

  return replaceArguments(usedTranslation, replacements.flat());
};

/** @param {import('@meli/i18n').Locale} [locale] */
const getBestLocale = (locale) => {
  if (!locale) return ES_AR;

  if (startsWith(locale, 'en')) return EN_US;

  if (startsWith(locale, 'zh')) return ZH_CN;

  return locale === PT_BR ? PT_BR : ES_AR;
};

/** @type {import('../..').InjectTranslations} */
const injectTranslations = (i18n, contextLocale, moduleName, availableTranslations) => {
  const bestLocale = getBestLocale(contextLocale);
  const componentTranslations = availableTranslations[bestLocale];

  // @ts-expect-error: disabled the rule because 'andes' is a custom property.
  if (!i18n.andes) {
    // @ts-expect-error: disabled the rule because 'andes' is a custom property.
    i18n.andes = {};
    i18n.pgettext = (context, text, ...replacements) => createI18nPgettext(i18n)(context, text, ...replacements);
    i18n.npgettext = (context, singular, plural, quantity, ...replacements) =>
      createI18nNPgettext(i18n)(context, singular, plural, quantity, ...replacements);
  }

  // @ts-expect-error: disabled the rule because 'andes' is a custom property.
  if (!i18n.andes[String(moduleName)]) {
    // @ts-expect-error: translations is not an exposed type, it is added in a custom way.
    i18n.andes.translations = { ...i18n.andes.translations, ...componentTranslations };
    // @ts-expect-error: disabled the rule because 'andes' is a custom property.
    i18n.andes[String(moduleName)] = true;
  }
};

/** @type {import('../..').GetPatchedI18n} */
const getPatchedI18n = (contextValue, moduleName, availableTranslations) => {
  const { i18n, locale = 'es-AR' } = /** @type {ContextValue} */ (contextValue);

  injectTranslations(i18n, locale, moduleName, availableTranslations);

  return i18n;
};

export { getBestLocale, getPatchedI18n, injectTranslations };
