import { getCsrfToken } from '@nordic/context';
import { getDeviceInfo } from '@nordic/context/internal';
import { getI18n } from '@nordic/i18n';

const useNordicContext = () => {
  try {
    const csrfToken = getCsrfToken();
    const deviceInfo = getDeviceInfo();
    const i18n = getI18n();

    const locale = i18n?.locale;
    const device = {
      mobile: deviceInfo?.type === 'mobile',
      nativeApp: {
        os: deviceInfo?.context,
      },
      osName: deviceInfo?.context,
      type: deviceInfo?.type,
      webView: deviceInfo?.webView,
    };

    return { csrfToken, device, i18n, locale };
  } catch (_error) {
    return undefined;
  }
};

export default useNordicContext;
