import { useContext } from 'react';
import warning from '@andes/common/build/utils/warning';
import useNordicProvider from './useNordicContext';
import { ES_AR } from '../constants/locales';
import AndesContext from '../AndesContext';
import { getPatchedI18n } from '../utils/translations';

const DEFAULT_LOCALE = ES_AR;

/** @typedef {import('../..').ContextValue} ContextValue */
/** @typedef {import('@meli/i18n').I18n} I18n */

/** @type {import('../..').UseCallAndesContext} */
const useCallAndesContext = (moduleName, andesTranslations) => {
  const contextValue = useContext(AndesContext);

  if (Object.keys(contextValue).length === 0) return;

  const patchedI18n = andesTranslations
    ? getPatchedI18n(/** @type {ContextValue} */ (contextValue), moduleName, andesTranslations)
    : { translations: {} };

  return { ...contextValue, i18n: /** @type {I18n} */ (patchedI18n) };
};

/** @type {import('../..').UseAndesContext} */
const useAndesContext = (moduleName = '@andes', andesTranslations) => {
  const nordicContext = useNordicProvider();

  // In Nordic environments, the NordicProvider context is imported.
  if (nordicContext) {
    return nordicContext;
  }

  // AndesProvider is imported in contexts outside Nordic.
  const andesContext = useCallAndesContext(moduleName, andesTranslations);

  if (andesContext) {
    return andesContext;
  }

  warning(false, `${moduleName} needs a valid configuration of <AndesProvider> on your application.
      Check the documentation about @andes/context and <AndesProvider> on:
      https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/context/README.md`);

  // Create a default i18n object with essential functions to prevent runtime errors
  const defaultI18n = {
    translations: {},
    pgettext: (/** @type {string} */ context, /** @type {string} */ text) => text,
    npgettext: (/** @type {string} */ context, /** @type {string} */ singular, /** @type {string} */ plural, /** @type {number} */ quantity) => (quantity === 1 ? singular : plural),
  };

  return {
    i18n: /** @type {I18n} */ (/** @type {unknown} */ (defaultI18n)),
    locale: DEFAULT_LOCALE,
    device: {
      mobile: undefined,
      type: undefined,
      webView: undefined,
    },
    csrfToken: '' };
};

export default useAndesContext;
